/**
 * @public
 */
export const PinnedStateValues = [
  /** The item is not displayed in the filter bar, but is available in the add-filter select and can change to a "pinned-optional" item at any time. */
  'optional',
  /** The item is currently displayed in the filter bar, but is available in the add-filter select and can change to an "optional" item at any time. */
  'pinned-optional',
  /** The item is always in the filter bar and not controllable with the add-filter select. Changing from "pinned" to any other state is also not recommended since that might break UX patterns.*/
  'pinned',
] as const;

/**
 * @public
 */
export type PinnedState = Record<string, (typeof PinnedStateValues)[number]>;

export type FilterBarAdditionPayload = {
  /** A unique identifier for this filter (must only be unique for this filter). */
  name: string | number;
  /** Value of the filter */
  value: unknown;
  /**
   * The current pinned state of the item.
   * @defaultValue pinned
   */
  pinnedState?: PinnedState;
};

export type FilterBarRemovalPayload = {
  /** A unique identifier for this filter (must only be unique for this filter). */
  name: string | number;
};

export type FilterBarUpdatePinnedState = {
  /**
   * The new pinned state of the item.
   * @defaultValue pinned
   */
  newPinnedState: PinnedState;
};

export type FilterBarPinnedStatePayload = {
  /** Array of keys that need to be pinned or unpinned. */
  keys: Array<string | number>;
};

export const enum FilterBarActions {
  INITIALIZE = 'initialize',
  CHANGE = 'change',
  REMOVE = 'remove',
  PIN = 'pin',
  UNPIN = 'unpin',
  CHANGEPINNEDSTATE = 'changepinnedstate',
}

export type FilterBarReducerAction =
  | { type: FilterBarActions.INITIALIZE; payload: FilterBarAdditionPayload }
  | { type: FilterBarActions.CHANGE; payload: FilterBarAdditionPayload }
  | {
      type: FilterBarActions.REMOVE;
      payload: FilterBarRemovalPayload;
    }
  | {
      type: FilterBarActions.PIN;
      payload: FilterBarPinnedStatePayload;
    }
  | {
      type: FilterBarActions.UNPIN;
      payload: FilterBarPinnedStatePayload;
    }
  | {
      type: FilterBarActions.CHANGEPINNEDSTATE;
      payload: FilterBarUpdatePinnedState;
    };
